// Parse input from backend orchestrate endpoint
const webhookRaw = $('Webhook').first().json;
const body = webhookRaw.body || webhookRaw;

const checkin_id = body.checkin_id || null;
const tag = (body.tag || '').trim().toLowerCase();
const slug = body.slug || null;
const pnr = body.personnummer || null;
const name = body.name || null;

return [{
  json: {
    checkin_id,
    tag,
    slug,
    personnummer: pnr,
    name,
    _runEbas: !!pnr,
    _runStartgg: !!tag && !!slug,
  }
}];

// Combine results from eBas and Start.gg checks
const ctx = $('Parse Input').first().json;

// Get eBas result
let ebas = { isMember: false };
try {
  const ebasItems = $('eBas Check').all();
  if (ebasItems.length > 0 && ebasItems[0].json && !ebasItems[0].json.error) {
    ebas = ebasItems[0].json;
  }
} catch (e) { /* treat as not member */ }

// Get Start.gg result
let sgg = { isRegistered: false, events: [] };
try {
  const sggItems = $('Start.gg Check').all();
  if (sggItems.length > 0 && sggItems[0].json && !sggItems[0].json.error) {
    sgg = sggItems[0].json;
  }
} catch (e) { /* treat as not registered */ }

const isActualMember = ebas.isMember === true;
const isActualStartgg = sgg.isRegistered === true;
const events = sgg.events || [];
const now = new Date().toISOString();

return [{ json: {
  checkin_id: ctx.checkin_id,
  member: isActualMember,
  startgg: isActualStartgg,
  events: events,
  _ebasOk: isActualMember,
  _startggOk: isActualStartgg,
  _ebasError: ebas.error || null,
  _startggError: sgg.error || null,
  fetched_at: now,
}}];

